import os
import requests
from io import BytesIO

from sklearn.externals import joblib
from google.cloud import storage

# Fetching the storage path from Environment variable
model_path = os.getenv('MODEL_PATH')

# Setting up the Google Cloud Storage client
client = storage.Client()
bucket = client.get_bucket('your_bucket_name')

def load_model():
  blobs = bucket.list_blobs(prefix=model_path)
  
  # Fetch the most recent model based on timestamp
  models = [(blob, blob.updated) for blob in blobs]
  latest_model = sorted(models, key=lambda tup: tup[1])[-1][0]

  # Download the latest model to a .pkl file
  byte_stream = BytesIO()
  latest_model.download_to_file(byte_stream)
  byte_stream.seek(0)

  model = joblib.load(byte_stream)

  return model

# Load the model on startup
model = load_model()